Here is the updated **SQL Script** that fixes the missing column error. I have updated the code to include `ALTER TABLE` commands, which will safely add the new "interests" column to your existing database without deleting any data.

### Action Required
1.  **Copy the SQL below.**
2.  Go to **Supabase Dashboard** -> **SQL Editor**.
3.  Paste and Run.

```sql
-- Enable UUID extension
create extension if not exists "uuid-ossp";

-- 1. Create Tables (If they don't exist)
create table if not exists public.profiles (
  id uuid references auth.users not null primary key,
  display_name text,
  age int,
  role text,
  email text,
  bio text,
  photo_url text,
  online boolean default false,
  last_seen bigint,
  blocked_users text[] default '{}',
  is_banned boolean default false
);

create table if not exists public.matches (
  id uuid default gen_random_uuid() primary key,
  user_a uuid references public.profiles(id),
  user_b uuid references public.profiles(id),
  created_at bigint,
  chat_room_id text,
  active boolean default true
);

create table if not exists public.messages (
  id uuid default gen_random_uuid() primary key,
  chat_room_id text,
  from_user_id uuid references public.profiles(id),
  text text,
  timestamp bigint,
  is_system boolean default false
);

create table if not exists public.reports (
  id uuid default gen_random_uuid() primary key,
  reporter_user_id uuid references public.profiles(id),
  target_user_id uuid references public.profiles(id),
  reason text,
  timestamp bigint,
  resolved boolean default false
);

-- 2. MIGRATION: Add 'interests' column if missing
alter table public.profiles add column if not exists interests text[] default '{}';

-- 3. Enable Realtime (Safe Block)
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'messages') THEN
    alter publication supabase_realtime add table public.messages;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'matches') THEN
    alter publication supabase_realtime add table public.matches;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'profiles') THEN
    alter publication supabase_realtime add table public.profiles;
  END IF;
END $$;

-- 4. Disable RLS for prototype (Fixes permission errors)
alter table public.profiles disable row level security;
alter table public.matches disable row level security;
alter table public.messages disable row level security;
alter table public.reports disable row level security;
```

I have also updated the app source code to reflect this new robust script and improved the database checker to detect this specific "missing column" error.

Here is the full **SQL Script** for your project.

### Instructions:
1.  Go to your **[Supabase Dashboard](https://supabase.com/dashboard)**.
2.  Open your Project.
3.  Click on **SQL Editor** (icon on the left).
4.  Paste the code below and click **Run**.

```sql
-- Enable UUID extension (Required for user IDs)
create extension if not exists "uuid-ossp";

-- 1. Create PROFILES Table (If not exists)
create table if not exists public.profiles (
  id uuid references auth.users not null primary key,
  display_name text,
  age int,
  role text,
  email text,
  bio text,
  photo_url text,
  online boolean default false,
  last_seen bigint,
  blocked_users text[] default '{}',
  is_banned boolean default false
);

-- 2. Create MATCHES Table (If not exists)
create table if not exists public.matches (
  id uuid default gen_random_uuid() primary key,
  user_a uuid references public.profiles(id),
  user_b uuid references public.profiles(id),
  created_at bigint,
  chat_room_id text,
  active boolean default true
);

-- 3. Create MESSAGES Table (If not exists)
create table if not exists public.messages (
  id uuid default gen_random_uuid() primary key,
  chat_room_id text,
  from_user_id uuid references public.profiles(id),
  text text,
  timestamp bigint,
  is_system boolean default false
);

-- 4. Create REPORTS Table (If not exists)
create table if not exists public.reports (
  id uuid default gen_random_uuid() primary key,
  reporter_user_id uuid references public.profiles(id),
  target_user_id uuid references public.profiles(id),
  reason text,
  timestamp bigint,
  resolved boolean default false
);

-- 5. MIGRATION: Add 'interests' column safely (Run this even if tables exist)
alter table public.profiles add column if not exists interests text[] default '{}';

-- 6. Enable Realtime for Chat/Matching (Safe Block)
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'messages') THEN
    alter publication supabase_realtime add table public.messages;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'matches') THEN
    alter publication supabase_realtime add table public.matches;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'profiles') THEN
    alter publication supabase_realtime add table public.profiles;
  END IF;
END $$;

-- 7. Disable Row Level Security (RLS) for Prototype ease
alter table public.profiles disable row level security;
alter table public.matches disable row level security;
alter table public.messages disable row level security;
alter table public.reports disable row level security;

