export const apiHeartbeat = async (userId: string) => {
    if (!userId) return false;
    try {
        const { error } = await supabase.from('profiles').update({
            last_seen: Date.now(),
            online: true
        }).eq('id', userId);

        // If error (e.g., user deleted by admin reset), return false
        if (error) return false;
        return true;
    } catch (e) {
        return false;
    }
};

