  }).join(' ');

  const { error } = await supabase.from('messages').insert({
      chat_room_id: chatRoomId,
      from_user_id: isSystem ? null : fromUserId, 
      text: cleanText,
      timestamp: Date.now(),
      is_system: isSystem
  });
  if (error) console.error("Send msg error", error);

  if (!isSystem && !error) {
      logAnalyticsEvent('send_message');
  }
};

