        // 2. Keep Supabase update for legacy compatibility (Matchmaking needs it)
        const { error } = await supabase.from('profiles').update({
            last_seen: Date.now(),
            online: true
        }).eq('id', userId);

        if (error) return false;
        return true;
    } catch (e) {
        return false;
    }
};

export const apiGetOnlineCountAsync = async () => {
